#ifndef NEOPIXEL_RING_H
#define NEOPIXEL_RING_H
void neo_ring_setup(uint16_t num);
void neo_ring_set(uint16_t i,uint8_t r,uint8_t g,uint8_t b);
void neo_ring_fill(uint8_t r,uint8_t g,uint8_t b);
void neo_ring_rainbow();
void neo_ring_progress(uint8_t pct,uint8_t r,uint8_t g,uint8_t b);
void neo_ring_clear();
#endif

firmware_template.source:
#include "neopixel_ring.h"
#include <Adafruit_NeoPixel.h>
#define RING_PIN 16
static Adafruit_NeoPixel*_ring=nullptr;static uint16_t _num=0;
void neo_ring_setup(uint16_t n){_num=n;_ring=new Adafruit_NeoPixel(n,RING_PIN,NEO_GRB+NEO_KHZ800);_ring->begin();_ring->setBrightness(50);_ring->show();Serial.printf("[ring] OK %d LEDs\n",n);}
void neo_ring_set(uint16_t i,uint8_t r,uint8_t g,uint8_t b){if(_ring&&i<_num){_ring->setPixelColor(i,_ring->Color(r,g,b));_ring->show();}}
void neo_ring_fill(uint8_t r,uint8_t g,uint8_t b){if(_ring){_ring->fill(_ring->Color(r,g,b));_ring->show();}}
void neo_ring_rainbow(){if(!_ring)return;for(uint16_t i=0;i<_num;i++){uint16_t h=(i*65535/_num+millis()*50)&0xFFFF;_ring->setPixelColor(i,_ring->gamma32(_ring->ColorHSV(h)));}_ring->show();}
void neo_ring_progress(uint8_t pct,uint8_t r,uint8_t g,uint8_t b){if(!_ring)return;uint16_t on=_num*pct/100;for(uint16_t i=0;i<_num;i++)_ring->setPixelColor(i,i<on?_ring->Color(r,g,b):0);_ring->show();}
void neo_ring_clear(){if(_ring){_ring->clear();_ring->show();}}
